func testAccChronicleDataTableRow_basic(context map[string]interface{}) string {
	return acctest.Nprintf(`
resource "google_chronicle_data_table" "example_dt" {
  location       = "us"
  instance = "%{instance_id}"
  data_table_id  = "tf_test_terraform_test%{random_suffix}"
  description    = "Sample DataTable for DataTableRow test"
  deletion_policy = "FORCE"
  column_info {
    column_index    = 0
    original_column = "username"
    column_type     = "STRING"
  }
  column_info {
    column_index    = 1
    original_column = "ip_address"
    column_type     = "CIDR"
  }
}

resource "google_chronicle_data_table_row" "example_row" {
  # Explicitly provide the URL parameters.
  location       = "us"
  instance       = "%{instance_id}"
  data_table_id  = google_chronicle_data_table.example_dt.data_table_id
  row_time_to_live = "%{ttl_initial}"
  values           = %{values_initial}
  depends_on       = [google_chronicle_data_table.example_dt]
}

output "data_table_row_name" {
  value = google_chronicle_data_table_row.example_row.name
}
`, context)
}

